param([Parameter(Mandatory=$true)][string]$Version); Write-Host "=== Build v$Version ===" -ForegroundColor Cyan; $publishDir = "publish\v$Version"; $zipFile = "publish\WpfApp2-v$Version.zip"; Write-Host "[1/3] Building..." -ForegroundColor Yellow; dotnet publish WpfApp2\WpfApp2.csproj -c Release -r win-x64 --self-contained false -o $publishDir -p:PublishSingleFile=false -p:PublishReadyToRun=false; if ($LASTEXITCODE -ne 0) { Write-Host "Build failed" -ForegroundColor Red; exit 1 }; Write-Host "[2/3] Creating ZIP..." -ForegroundColor Yellow; if (Test-Path $zipFile) { Remove-Item $zipFile -Force }; Compress-Archive -Path "$publishDir\*" -DestinationPath $zipFile -CompressionLevel Optimal; Write-Host "[3/3] Complete!" -ForegroundColor Green; Write-Host "Location: $zipFile" -ForegroundColor Cyan; explorer.exe publish